on conflict (id) do update set
  name = excluded.name,
  ward_number = excluded.ward_number,
  zone_name = excluded.zone_name,
  status = excluded.status,
  verification_status = excluded.verification_status,
  verification_notes = excluded.verification_notes,
  is_placeholder = excluded.is_placeholder,
  is_routing_eligible = excluded.is_routing_eligible,
  last_verified_on = excluded.last_verified_on,
  reference_source_id = excluded.reference_source_id,
  import_record_id = excluded.import_record_id;

insert into governance.departments (
  id,
  code,
  name,
  applicable_body_types,
  complaint_types,
  typical_coverage,
  required_data,
  priority_guidance,
  status,
  verification_status,
  verification_notes,
  is_placeholder,
  is_routing_eligible,
  last_verified_on,
  reference_source_id,
  import_record_id
)
