$bmc_mobile_demo_governance_core$;

do $bmc_mobile_demo_part_1_verify$
begin
  if (
    select count(*)
    from routing.issue_categories
    where code = any(array[
      'garbage_dump', 'missed_sweeping', 'pothole', 'blocked_drain',
      'sewage_overflow', 'water_leakage', 'broken_streetlight', 'open_manhole',
      'mosquito_breeding', 'illegal_construction', 'encroachment', 'fallen_tree'
    ]::text[])
  ) <> 12 then
    raise exception using errcode = '55000', message = 'BMC_MOBILE_DEMO_CATEGORY_COUNT_INVALID';
  end if;

  if not exists (
    select 1
    from governance.local_bodies as local_body
    inner join governance.authorities as authority on authority.id = local_body.authority_id
    where local_body.id = 'fa1e71b4-01e3-5e72-92e8-1476eec1adcd'
      and authority.id = '3fabe3b8-47cf-58fe-a59c-bb34bd02322a'
      and local_body.verification_status = 'verified'
      and local_body.is_routing_eligible
      and authority.verification_status = 'verified'
      and authority.is_routing_eligible
  ) then
    raise exception using errcode = '55000', message = 'BMC_MOBILE_DEMO_CORE_NOT_ELIGIBLE';
  end if;
end;
$bmc_mobile_demo_part_1_verify$;

commit;
